DigitFrequenciesInTheThePowersOfTwo[n_Integer?Positive] :=
  Module[{numString, charCounts, result},
    numString = ToString[2^n];
    charCounts = Counts[Characters[numString]];
    result = Table[Lookup[charCounts, ToString[i], 0], {i, 0, 9}];
    result
  ]

BilliardPolygon[poly_, start_, dir_, bounces_] := Module[{
   vertices = N[poly],
   currentPos = N[start],
   currentDir = Normalize[N[dir] - N[start]],
   path = {N[start]},
   numBounces = 0,
   epsilon = 10^-6
   },

  While[numBounces < bounces,
   Block[{
     minDist = Infinity,
     nextPos = {},
     nextWallNormal = {},
     nextWallIndex = -1
     },

    Do[
     Block[{
       p1 = vertices[[i]],
       p2 = vertices[[Mod[i, Length[vertices]] + 1]],
       wallDir = Normalize[p2 - p1],
       wallNormal = {-wallDir[[2]], wallDir[[1]]},
       t, u, intersection
       },

      (* Solve for intersection of ray and wall segment *)
      (* currentPos + t * currentDir == p1 + u * (p2 - p1) *)
      (* t * currentDir - u * (p2 - p1) == p1 - currentPos *)
      If[Abs[Det[{currentDir, p2 - p1}]] > epsilon,
       {t, u} = LinearSolve[{currentDir, -(p2 - p1)}\[Transpose], p1 - currentPos];

       If[t > epsilon && -epsilon <= u <= 1 + epsilon,
        intersection = currentPos + t * currentDir;

        (* Check if intersection is within polygon (to handle cases where ray goes "backwards" through a wall) *)
        If[Graphics`Mesh`PointInPolygonQ[vertices, intersection],
         If[t < minDist,
          minDist = t;
          nextPos = intersection;
          nextWallNormal = If[Dot[currentDir, wallNormal] < 0, wallNormal, -wallNormal];
          nextWallIndex = i;
          ]
         ]
        ]
       ]
      ],
     {i, 1, Length[vertices]}
     ];

    If[minDist == Infinity, Break[]]; (* No intersection found, should not happen for convex polygons *)

    (* Check for corner proximity *)
    If[AnyTrue[vertices, Norm[# - nextPos] < epsilon &],
     AppendTo[path, nextPos];
     Break[]
     ];

    AppendTo[path, nextPos];
    currentPos = nextPos;
    currentDir = currentDir - 2 * Dot[currentDir, nextWallNormal] * nextWallNormal;
    numBounces++;
    ];
  path
  ]
